void sparse_matvec(int n, const int *rowptr, const int *colidx, const double *values, const double *x, double *y)
{
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        int start = rowptr[i];
        int end = rowptr[i + 1];
        int j = start;
        // 4x Loop Unrolling
        for (; j <= end - 4; j += 4) {
            sum += values[j] * x[colidx[j]];
            sum += values[j+1] * x[colidx[j+1]];
            sum += values[j+2] * x[colidx[j+2]];
            sum += values[j+3] * x[colidx[j+3]];
        }
        for (; j < end; j++) {
            sum += values[j] * x[colidx[j]];
        }
        y[i] = sum;
    }
}

double dot_product(const double *x, const double *y, int n)
{
    double sum = 0.0;
    #pragma omp parallel for reduction(+:sum) schedule(static)
    for (int i = 0; i < n; i++) {
        sum += x[i] * y[i];
    }
    return sum;
}
